function ReportManager:onPlayerLogout(player)
    local time = os.time() - player.inGameTime
    GameAnalytics:sessionEnd(player.userId, time)
    ReportManager:reportUserTime(player.userId, time)
    if player.appIntegral > 0 then
        ReportManager:reportUserIntegral(player.userId, player.appIntegral)
    end
    player.appIntegral = 0
end

function ReportManager:getUserReportCache(userId)
    userId = tonumber(tostring(userId))
    for _, cache in pairs(WaitReportCache) do
        if cache.userId == userId then
            return cache
        end
    end
    local versionCode = "1"
    local packageName = "com.sandboxol.blockymods"
    local info = GameAnalyticsCache:getClientInfo(userId)
    if info ~= nil then
        versionCode = info.version_code or "1"
        packageName = info.package_name or "com.sandboxol.blockymods"
    end
    local isIndieGame = 0
    local player = PlayerManager:getPlayerByUserId(userId)
    if player ~= nil and player.enableIndie then
        isIndieGame = 1
    end
    local cache = {
        userId = userId,
        gameId = GameType,
        kill = 0,
        rank = 0,
        meanTime = 0,
        integral = 0,
        type = 0,
        isIndieGame = isIndieGame,
        appVersion = versionCode,
        packageName = packageName,
        engineVersion = EngineVersionSetting.getEngineVersion()
    }
    local roundIdKey = tostring(userId) .. "-" .. WebService.gameId
    if not RoundIdReportLock[roundIdKey] then
        cache.roundId = WebService.gameId
        RoundIdReportLock[roundIdKey] = true
    end
    table.insert(WaitReportCache, cache)
    return cache
end

